  1→/**
  2→ * MCP Server Auth Acceptance Test Kit
  3→ *
  4→ * Domain-specific helpers for MCP server authentication acceptance tests.
  5→ * Uses MSW to simulate external MCP servers and OAuth authorization servers.
  6→ *
  7→ * Driving ports:
  8→ *   POST   /api/workspaces/:wsId/mcp-servers                     (create MCP server with auth)
  9→ *   PUT    /api/workspaces/:wsId/mcp-servers/:id/headers          (update static headers)
 10→ *   POST   /api/workspaces/:wsId/mcp-servers/:id/discover-auth    (trigger OAuth discovery)
 11→ *   GET    /api/workspaces/:wsId/mcp-servers/:id/auth-status      (auth status)
 12→ *   GET    /oauth/callback                                        (OAuth callback)
 13→ */
 14→import { RecordId, type Surreal } from "surrealdb";
 15→import {
 16→  setupAcceptanceSuite,
 17→  createTestUserWithMcp,
 18→  type AcceptanceTestRuntime,
 19→  type TestUserWithMcp,
 20→} from "../acceptance-test-kit";
 21→import { http, HttpResponse } from "msw";
 22→import { setupServer as setupMswServer } from "msw/node";
 23→
 24→// Re-export shared helpers
 25→export {
 26→  setupAcceptanceSuite,
 27→  createTestUserWithMcp,
 28→  type AcceptanceTestRuntime,
 29→  type TestUserWithMcp,
 30→};
 31→
 32→// ---------------------------------------------------------------------------
 33→// MSW Mock OAuth/MCP Server
 34→// ---------------------------------------------------------------------------
 35→
 36→export type MockMcpServerConfig = {
 37→  /** Base URL the mock MCP server listens on (e.g. https://mcp.example.com) */
 38→  mcpServerUrl: string;
 39→  /** Base URL of the mock auth server (e.g. https://auth.example.com) */
 40→  authServerUrl?: string;
 41→  /** Scopes the protected resource supports */
 42→  scopesSupported?: string[];
 43→  /** Whether the auth server supports dynamic registration */
 44→  supportsDynamicRegistration?: boolean;
 45→  /** Expected authorization header value for authenticated requests */
 46→  expectedAuthHeader?: string;
 47→  /** Captured requests for assertion */
 48→  capturedRequests?: CapturedRequest[];
 49→};
 50→
 51→export type CapturedRequest = {
 52→  url: string;
 53→  method: string;
 54→  headers: Record<string, string>;
 55→};
 56→
 57→/**
 58→ * Creates MSW handlers that simulate an MCP server with OAuth 2.1 support.
 59→ *
 60→ * - Protected Resource Metadata at /.well-known/oauth-protected-resource
 61→ * - Auth Server Metadata at /.well-known/oauth-authorization-server
 62→ * - Token endpoint at /token
 63→ * - Optional dynamic registration at /register
 64→ * - MCP endpoint that requires auth (returns 401 without, 200 with)
 65→ */
 66→export function createMockMcpHandlers(config: MockMcpServerConfig) {
 67→  const {
 68→    mcpServerUrl,
 69→    authServerUrl = "https://auth.example.com",
 70→    scopesSupported = ["read", "write"],
 71→    supportsDynamicRegistration = false,
 72→    expectedAuthHeader,
 73→    capturedRequests = [],
 74→  } = config;
 75→
 76→  return [
 77→    // Protected Resource Metadata (RFC 9728)
 78→    http.get(`${mcpServerUrl}/.well-known/oauth-protected-resource`, () => {
 79→      return HttpResponse.json({
 80→        resource: mcpServerUrl,
 81→        authorization_servers: [authServerUrl],
 82→        scopes_supported: scopesSupported,
 83→        bearer_methods_supported: ["header"],
 84→      });
 85→    }),
 86→
 87→    // Auth Server Metadata (RFC 8414)
 88→    http.get(`${authServerUrl}/.well-known/oauth-authorization-server`, () => {
 89→      const metadata: Record<string, unknown> = {
 90→        issuer: authServerUrl,
 91→        authorization_endpoint: `${authServerUrl}/authorize`,
 92→        token_endpoint: `${authServerUrl}/token`,
 93→        scopes_supported: scopesSupported,
 94→        response_types_supported: ["code"],
 95→        code_challenge_methods_supported: ["S256"],
 96→        grant_types_supported: ["authorization_code", "refresh_token"],
 97→      };
 98→
 99→      if (supportsDynamicRegistration) {
100→        metadata.registration_endpoint = `${authServerUrl}/register`;
101→      }
102→
103→      return HttpResponse.json(metadata);
104→    }),
105→
106→    // Token endpoint — validates code + code_verifier, returns tokens
107→    http.post(`${authServerUrl}/token`, async ({ request }) => {
108→      const body = await request.text();
109→      const params = new URLSearchParams(body);
110→      const grantType = params.get("grant_type");
111→
112→      if (grantType === "authorization_code") {
113→        const code = params.get("code");
114→        const codeVerifier = params.get("code_verifier");
115→
116→        if (!code || !codeVerifier) {
117→          return HttpResponse.json(
118→            { error: "invalid_request", error_description: "Missing code or code_verifier" },
119→            { status: 400 },
120→          );
121→        }
122→
123→        return HttpResponse.json({
124→          access_token: `mock-access-token-${crypto.randomUUID().slice(0, 8)}`,
125→          token_type: "Bearer",
126→          expires_in: 3600,
127→          refresh_token: `mock-refresh-token-${crypto.randomUUID().slice(0, 8)}`,
128→          scope: scopesSupported.join(" "),
129→        });
130→      }
131→
132→      if (grantType === "refresh_token") {
133→        const refreshToken = params.get("refresh_token");
134→        if (!refreshToken) {
135→          return HttpResponse.json(
136→            { error: "invalid_grant", error_description: "Missing refresh_token" },
137→            { status: 400 },
138→          );
139→        }
140→
141→        return HttpResponse.json({
142→          access_token: `mock-refreshed-token-${crypto.randomUUID().slice(0, 8)}`,
143→          token_type: "Bearer",
144→          expires_in: 3600,
145→          refresh_token: `mock-refresh-token-${crypto.randomUUID().slice(0, 8)}`,
146→        });
147→      }
148→
149→      return HttpResponse.json(
150→        { error: "unsupported_grant_type" },
151→        { status: 400 },
152→      );
153→    }),
154→
155→    // Dynamic registration (RFC 7591)
156→    http.post(`${authServerUrl}/register`, async ({ request }) => {
157→      if (!supportsDynamicRegistration) {
158→        return new HttpResponse(null, { status: 404 });
159→      }
160→
161→      const body = await request.json() as Record<string, unknown>;
162→      return HttpResponse.json({
163→        client_id: `dynamic-client-${crypto.randomUUID().slice(0, 8)}`,
164→        client_secret: `dynamic-secret-${crypto.randomUUID().slice(0, 8)}`,
165→        client_name: body.client_name,
166→        redirect_uris: body.redirect_uris,
167→      });
168→    }),
169→
170→    // MCP server endpoint — requires auth, captures requests
171→    http.post(mcpServerUrl, ({ request }) => {
172→      capturedRequests.push({
173→        url: request.url,
174→        method: request.method,
175→        headers: Object.fromEntries(request.headers.entries()),
176→      });
177→
178→      const authHeader = request.headers.get("authorization");
179→
180→      if (expectedAuthHeader && authHeader !== expectedAuthHeader) {
181→        return new HttpResponse(null, {
182→          status: 401,
183→          headers: {
184→            "WWW-Authenticate": `Bearer resource_metadata="${mcpServerUrl}/.well-known/oauth-protected-resource"`,
185→          },
186→        });
187→      }
188→
189→      // Return a valid MCP tools/list response
190→      return HttpResponse.json({
191→        jsonrpc: "2.0",
192→        id: 1,
193→        result: {
194→          tools: [
195→            {
196→              name: "mock_tool",
197→              description: "A mock tool for testing",
198→              inputSchema: { type: "object", properties: {} },
199→            },
200→          ],
201→        },
202→      });
203→    }),
204→  ];
205→}
206→
207→/**
208→ * Sets up MSW server with mock MCP/OAuth handlers.
209→ * Returns the server and captured requests array.
210→ */
211→export function setupMockMcpServer(config: MockMcpServerConfig) {
212→  const capturedRequests: CapturedRequest[] = [];
213→  const handlers = createMockMcpHandlers({ ...config, capturedRequests });
214→  const msw = setupMswServer(...handlers);
215→  return { msw, capturedRequests };
216→}
217→
218→// ---------------------------------------------------------------------------
219→// SurrealDB Seed Helpers
220→// ---------------------------------------------------------------------------
221→
222→export type SeedMcpServerOptions = {
223→  name: string;
224→  url: string;
225→  transport?: "sse" | "streamable-http";
226→  authMode?: "none" | "static_headers" | "oauth" | "provider";
227→  staticHeaders?: Array<{ name: string; value_encrypted: string }>;
228→  workspaceId: string;
229→};
230→
231→/**
232→ * Seed an mcp_server record directly in SurrealDB.
233→ */
234→export async function seedMcpServer(
235→  surreal: Surreal,
236→  serverId: string,
237→  options: SeedMcpServerOptions,
238→): Promise<string> {
239→  const serverRecord = new RecordId("mcp_server", serverId);
240→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
241→
242→  const content: Record<string, unknown> = {
243→    name: options.name,
244→    url: options.url,
245→    transport: options.transport ?? "streamable-http",
246→    auth_mode: options.authMode ?? "none",
247→    workspace: workspaceRecord,
248→    tool_count: 0,
249→    created_at: new Date(),
250→  };
251→
252→  if (options.staticHeaders) {
