204→## Migration Script
205→
206→File: `schema/migrations/NNNN_mcp_server_auth_modes.surql`
207→
208→```sql
209→BEGIN TRANSACTION;
210→
211→-- Add auth_mode to mcp_server (default "none" for existing servers)
212→DEFINE FIELD OVERWRITE auth_mode ON mcp_server TYPE string
213→  DEFAULT "none"
214→  ASSERT $value IN ["none", "static_headers", "oauth", "provider"];
215→
216→-- Existing servers with a provider reference → set auth_mode to "provider"
217→UPDATE mcp_server SET auth_mode = "provider" WHERE provider IS NOT NONE;
218→
219→-- Static headers storage
220→DEFINE FIELD OVERWRITE static_headers ON mcp_server TYPE option<array<object>>;
221→DEFINE FIELD OVERWRITE static_headers[*].name ON mcp_server TYPE string;
222→DEFINE FIELD OVERWRITE static_headers[*].value_encrypted ON mcp_server TYPE string;
223→
224→-- OAuth account link
225→DEFINE FIELD OVERWRITE oauth_account ON mcp_server TYPE option<record<connected_account>>;
226→
227→-- Discovery source on credential_provider
228→DEFINE FIELD OVERWRITE discovery_source ON credential_provider TYPE option<string>;
229→
230→COMMIT TRANSACTION;
231→```
