 33→export async function serverNameExists(
 34→  surreal: Surreal,
 35→  workspaceRecord: RecordId<"workspace", string>,
 36→  name: string,
 37→): Promise<boolean> {
 38→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
 39→    `SELECT id FROM mcp_server WHERE workspace = $ws AND name = $name LIMIT 1;`,
