  1→/**
  2→ * Credential Resolver -- resolves and injects auth headers for integration tools.
  3→ *
  4→ * Pure core: buildAuthHeaders (auth_method + decrypted creds -> headers)
  5→ * Effect shell: resolveCredentialsForTool (DB query + decrypt + build headers)
  6→ *
  7→ * Resolution chain: mcp_tool.name -> mcp_tool.provider -> credential_provider
  8→ *   -> connected_account (WHERE identity=$id AND provider=$provider AND status=active)
  9→ *   -> decrypt -> build auth headers by auth_method.
 10→ *
 11→ * Step 07-01 in the MCP tool registry feature.
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import { decryptSecret } from "../tool-registry/encryption";
 15→import type { AuthMethod } from "../tool-registry/types";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Types
 19→// ---------------------------------------------------------------------------
 20→
 21→/** Successful credential resolution: headers to inject into the outgoing request. */
 22→export type CredentialSuccess = {
 23→  readonly ok: true;
 24→  readonly headers: Record<string, string>;
 25→};
 26→
 27→/** Failed credential resolution: error message for the LLM. */
 28→export type CredentialError = {
 29→  readonly ok: false;
 30→  readonly error: string;
 31→};
 32→
 33→/** Result of credential resolution. */
 34→export type CredentialResult = CredentialSuccess | CredentialError;
 35→
 36→/** Dependencies for the credential resolver effect shell. */
 37→export type CredentialResolverDeps = {
 38→  readonly surreal: Surreal;
 39→  readonly toolEncryptionKey: string;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Pure Core: buildAuthHeaders
 44→// ---------------------------------------------------------------------------
 45→
 46→/** Decrypted credential fields from a connected_account. */
 47→export type DecryptedCredentials = {
 48→  readonly authMethod: AuthMethod;
 49→  readonly apiKey?: string;
 50→  readonly apiKeyHeader?: string;
 51→  readonly bearerToken?: string;
 52→  readonly basicUsername?: string;
 53→  readonly basicPassword?: string;
 54→  readonly accessToken?: string;
 55→};
 56→
 57→/**
 58→ * Build auth headers from decrypted credentials.
 59→ * Pure function: no IO, no side effects.
 60→ */
 61→export function buildAuthHeaders(
 62→  credentials: DecryptedCredentials,
 63→): CredentialResult {
 64→  switch (credentials.authMethod) {
 65→    case "api_key": {
 66→      if (!credentials.apiKey) {
 67→        return { ok: false, error: "API key not found in connected account" };
 68→      }
 69→      const headerName = credentials.apiKeyHeader || "X-API-Key";
 70→      return { ok: true, headers: { [headerName]: credentials.apiKey } };
 71→    }
 72→
 73→    case "basic": {
 74→      if (!credentials.basicUsername || !credentials.basicPassword) {
 75→        return { ok: false, error: "Basic auth credentials incomplete" };
 76→      }
 77→      const encoded = btoa(`${credentials.basicUsername}:${credentials.basicPassword}`);
 78→      return { ok: true, headers: { Authorization: `Basic ${encoded}` } };
 79→    }
 80→
 81→    case "bearer": {
 82→      if (!credentials.bearerToken) {
 83→        return { ok: false, error: "Bearer token not found in connected account" };
 84→      }
 85→      return { ok: true, headers: { Authorization: `Bearer ${credentials.bearerToken}` } };
 86→    }
 87→
 88→    case "oauth2": {
 89→      if (!credentials.accessToken) {
 90→        return { ok: false, error: "OAuth2 access token not found in connected account" };
 91→      }
 92→      return { ok: true, headers: { Authorization: `Bearer ${credentials.accessToken}` } };
 93→    }
 94→  }
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// DB Row Types (internal)
 99→// ---------------------------------------------------------------------------
100→
101→type ToolProviderRow = {
102→  provider: RecordId<"credential_provider", string>;
103→};
104→
105→type ProviderRow = {
106→  id: RecordId<"credential_provider", string>;
107→  auth_method: AuthMethod;
108→  api_key_header?: string;
109→  token_url?: string;
110→  client_id?: string;
111→  client_secret_encrypted?: string;
112→};
113→
114→type AccountRow = {
115→  id: RecordId<"connected_account", string>;
116→  status: string;
117→  api_key_encrypted?: string;
118→  bearer_token_encrypted?: string;
119→  basic_username?: string;
120→  basic_password_encrypted?: string;
121→  access_token_encrypted?: string;
122→  refresh_token_encrypted?: string;
123→  token_expires_at?: string | Date;
124→};
125→
126→// ---------------------------------------------------------------------------
127→// Effect Shell: resolveCredentialsForTool
128→// ---------------------------------------------------------------------------
129→
130→/**
131→ * Resolve credentials for an integration tool call.
132→ *
133→ * Resolution chain:
134→ *   1. Look up mcp_tool by name -> get provider reference
135→ *   2. Load credential_provider record -> get auth_method + config
136→ *   3. Find connected_account for identity + provider (status=active)
137→ *   4. Decrypt credential fields
138→ *   5. Build auth headers based on auth_method
139→ *
140→ * Handles: missing account, revoked account, expired OAuth2 tokens.
141→ */
142→export async function resolveCredentialsForTool(
143→  toolName: string,
144→  identityId: string,
145→  deps: CredentialResolverDeps,
146→): Promise<CredentialResult> {
147→  const { surreal, toolEncryptionKey } = deps;
148→  const identityRecord = new RecordId("identity", identityId);
149→
150→  // Step 1: Find the tool's provider reference
151→  const toolResults = await surreal.query<[ToolProviderRow[]]>(
152→    `SELECT provider FROM mcp_tool WHERE name = $name AND provider != NONE LIMIT 1;`,
153→    { name: toolName },
154→  );
155→
156→  const toolRow = (toolResults[0] ?? [])[0];
157→  if (!toolRow?.provider) {
158→    return { ok: false, error: "Tool has no credential provider configured" };
159→  }
160→
161→  const providerRecord = toolRow.provider;
162→
163→  // Step 2: Load the credential provider
164→  const providerResults = await surreal.query<[ProviderRow[]]>(
165→    `SELECT id, auth_method, api_key_header, token_url, client_id, client_secret_encrypted FROM $provider;`,
166→    { provider: providerRecord },
167→  );
168→
169→  const provider = (providerResults[0] ?? [])[0];
170→  if (!provider) {
171→    return { ok: false, error: "Credential provider not found" };
172→  }
173→
174→  // Step 3: Find the connected account for this identity + provider
175→  const accountResults = await surreal.query<[AccountRow[]]>(
176→    `SELECT * FROM connected_account WHERE identity = $identity AND provider = $provider LIMIT 1;`,
177→    { identity: identityRecord, provider: providerRecord },
178→  );
179→
180→  const account = (accountResults[0] ?? [])[0];
181→  if (!account) {
182→    return { ok: false, error: "Provider account not connected" };
183→  }
184→
185→  if (account.status === "revoked") {
186→    return { ok: false, error: "Provider account disconnected" };
187→  }
188→
189→  if (account.status === "expired") {
190→    return { ok: false, error: "Provider credentials expired, please reconnect" };
191→  }
192→
193→  // Step 4: Handle OAuth2 token refresh if expired
194→  if (provider.auth_method === "oauth2" && isTokenExpired(account.token_expires_at)) {
195→    const refreshResult = await refreshOAuth2Token(account, provider, deps);
196→    if (!refreshResult.ok) {
197→      return refreshResult;
198→    }
199→    // Use the refreshed token
200→    return { ok: true, headers: { Authorization: `Bearer ${refreshResult.accessToken}` } };
201→  }
202→
203→  // Step 5: Decrypt and build auth headers
204→  const decrypted = decryptAccountCredentials(account, provider, toolEncryptionKey);
205→  return buildAuthHeaders(decrypted);
206→}
207→
208→// ---------------------------------------------------------------------------
209→// Internal Helpers
210→// ---------------------------------------------------------------------------
211→
212→function isTokenExpired(tokenExpiresAt?: string | Date): boolean {
213→  if (!tokenExpiresAt) return false;
214→  const expiresAt = tokenExpiresAt instanceof Date
215→    ? tokenExpiresAt.getTime()
216→    : new Date(tokenExpiresAt).getTime();
217→  return expiresAt < Date.now();
218→}
219→
220→function decryptAccountCredentials(
221→  account: AccountRow,
222→  provider: ProviderRow,
223→  encryptionKey: string,
224→): DecryptedCredentials {
225→  return {
226→    authMethod: provider.auth_method,
227→    apiKey: account.api_key_encrypted
228→      ? decryptSecret(account.api_key_encrypted, encryptionKey)
229→      : undefined,
230→    apiKeyHeader: provider.api_key_header,
231→    bearerToken: account.bearer_token_encrypted
232→      ? decryptSecret(account.bearer_token_encrypted, encryptionKey)
233→      : undefined,
234→    basicUsername: account.basic_username,
235→    basicPassword: account.basic_password_encrypted
236→      ? decryptSecret(account.basic_password_encrypted, encryptionKey)
237→      : undefined,
238→    accessToken: account.access_token_encrypted
239→      ? decryptSecret(account.access_token_encrypted, encryptionKey)
240→      : undefined,
241→  };
242→}
243→
244→// ---------------------------------------------------------------------------
245→// OAuth2 Token Refresh
246→// ---------------------------------------------------------------------------
247→
248→type RefreshSuccess = { ok: true; accessToken: string };
249→type RefreshError = { ok: false; error: string };
250→
251→async function refreshOAuth2Token(
252→  account: AccountRow,
253→  provider: ProviderRow,
254→  deps: CredentialResolverDeps,
255→): Promise<RefreshSuccess | RefreshError> {
256→  const { surreal, toolEncryptionKey } = deps;
257→
258→  if (!account.refresh_token_encrypted || !provider.token_url) {
259→    // Mark account as expired
260→    await surreal.query(`UPDATE $acct SET status = 'expired', updated_at = time::now();`, {
261→      acct: account.id,
262→    });
263→    return { ok: false, error: "Provider credentials expired, please reconnect" };
264→  }
265→
266→  const refreshToken = decryptSecret(account.refresh_token_encrypted, toolEncryptionKey);
267→
268→  try {
269→    const tokenResponse = await fetch(provider.token_url, {
270→      method: "POST",
271→      headers: { "Content-Type": "application/x-www-form-urlencoded" },
272→      body: new URLSearchParams({
273→        grant_type: "refresh_token",
274→        refresh_token: refreshToken,
275→        client_id: provider.client_id ?? "",
276→        ...(provider.client_secret_encrypted
277→          ? { client_secret: decryptSecret(provider.client_secret_encrypted, toolEncryptionKey) }
278→          : {}),
279→      }),
280→    });
281→
282→    if (!tokenResponse.ok) {
283→      // Refresh failed -- mark account as expired
284→      await surreal.query(`UPDATE $acct SET status = 'expired', updated_at = time::now();`, {
285→        acct: account.id,
286→      });
287→      return { ok: false, error: "Provider credentials expired, please reconnect" };
288→    }
289→
290→    const tokenData = (await tokenResponse.json()) as {
291→      access_token: string;
292→      expires_in?: number;
293→      refresh_token?: string;
294→    };
295→
296→    // Encrypt new tokens and update the account
297→    const newAccessTokenEncrypted = encryptSecretForUpdate(tokenData.access_token, toolEncryptionKey);
298→    const expiresAt = tokenData.expires_in
299→      ? new Date(Date.now() + tokenData.expires_in * 1000)
300→      : undefined;
301→
302→    const updateParts = [
303→      `access_token_encrypted = $newToken`,
304→      `updated_at = time::now()`,
305→    ];
306→    const bindings: Record<string, unknown> = {
307→      acct: account.id,
308→      newToken: newAccessTokenEncrypted,
309→    };
310→
311→    if (expiresAt) {
312→      updateParts.push(`token_expires_at = $expiresAt`);
313→      bindings.expiresAt = expiresAt;
314→    }
315→
316→    if (tokenData.refresh_token) {
317→      const newRefreshEncrypted = encryptSecretForUpdate(tokenData.refresh_token, toolEncryptionKey);
318→      updateParts.push(`refresh_token_encrypted = $newRefresh`);
319→      bindings.newRefresh = newRefreshEncrypted;
320→    }
321→
322→    await surreal.query(`UPDATE $acct SET ${updateParts.join(", ")};`, bindings);
323→
324→    return { ok: true, accessToken: tokenData.access_token };
325→  } catch {
326→    // Network error during refresh -- mark as expired
327→    await surreal.query(`UPDATE $acct SET status = 'expired', updated_at = time::now();`, {
328→      acct: account.id,
329→    });
330→    return { ok: false, error: "Provider credentials expired, please reconnect" };
331→  }
332→}
333→
334→/** Import encrypt for token refresh updates. */
335→import { encryptSecret as encryptSecretForUpdate } from "../tool-registry/encryption";
