  1→/**
  2→ * MCP Client Module
  3→ *
  4→ * Provides functions to connect to upstream MCP servers, list tools,
  5→ * call tools, and disconnect. Supports SSE and Streamable HTTP transports.
  6→ *
  7→ * The McpClientFactory type is injectable via ServerDependencies so tests
  8→ * can substitute an InMemoryTransport-based factory.
  9→ *
 10→ * ADR-071: connect-per-request -- connections are established per proxy
 11→ * request, reused within request for multiple tool calls, and closed
 12→ * when the proxy request completes. No persistent connection pool.
 13→ */
 14→import { Client } from "@modelcontextprotocol/sdk/client/index.js";
 15→import { SSEClientTransport } from "@modelcontextprotocol/sdk/client/sse.js";
 16→import { StreamableHTTPClientTransport } from "@modelcontextprotocol/sdk/client/streamableHttp.js";
 17→import type { Transport } from "@modelcontextprotocol/sdk/shared/transport.js";
 18→import type {
 19→  ServerCapabilities,
 20→  Implementation as ServerInfo,
 21→} from "@modelcontextprotocol/sdk/types.js";
 22→import type { McpTransport } from "./types";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→/** Result of Client.listTools() */
 29→export type ToolListResult = Awaited<ReturnType<Client["listTools"]>>;
 30→
 31→/** Result of Client.callTool() */
 32→export type CallToolResult = Awaited<ReturnType<Client["callTool"]>>;
 33→
 34→/**
 35→ * Result of a successful MCP server connection.
 36→ */
 37→export type McpConnectionResult = {
 38→  client: Client;
 39→  serverInfo: ServerInfo;
 40→  capabilities: ServerCapabilities;
 41→};
 42→
 43→/**
 44→ * Injectable factory for MCP client operations.
 45→ * Injected via ServerDependencies so tests can provide a mock implementation
 46→ * backed by InMemoryTransport.
 47→ */
 48→export type McpClientFactory = {
 49→  connect: (
 50→    url: string,
 51→    transport: McpTransport,
 52→    headers?: Record<string, string>,
 53→  ) => Promise<McpConnectionResult>;
 54→  fetchToolList: (client: Client) => Promise<ToolListResult>;
 55→  callTool: (
 56→    client: Client,
 57→    name: string,
 58→    args: Record<string, unknown>,
 59→  ) => Promise<CallToolResult>;
 60→  disconnect: (client: Client) => Promise<void>;
 61→};
 62→
 63→// ---------------------------------------------------------------------------
 64→// Pure functions
 65→// ---------------------------------------------------------------------------
 66→
 67→const CONNECTION_TIMEOUT_MS = 10_000;
 68→
 69→/**
 70→ * Build auth headers from optional header map.
 71→ * Pure pass-through -- credential formatting (Bearer, Basic, api_key header)
 72→ * is handled by the credential provider layer before reaching this function.
 73→ */
 74→export function buildAuthHeaders(
 75→  headers?: Record<string, string>,
 76→): Record<string, string> {
 77→  return headers ?? {};
 78→}
 79→
 80→/**
 81→ * Create the appropriate MCP transport based on transport type.
 82→ * Injects auth headers into the transport's requestInit.
 83→ */
 84→export function createTransport(
 85→  url: string,
 86→  transportType: McpTransport,
 87→  headers?: Record<string, string>,
 88→): Transport {
 89→  const parsedUrl = new URL(url);
 90→  const authHeaders = buildAuthHeaders(headers);
 91→  const requestInit: RequestInit = {
 92→    headers: authHeaders,
 93→  };
 94→
 95→  switch (transportType) {
 96→    case "sse":
 97→      return new SSEClientTransport(parsedUrl, {
 98→        fetch: createFetchWithHeaders(authHeaders),
 99→        requestInit,
100→      });
101→    case "streamable-http":
102→      return new StreamableHTTPClientTransport(parsedUrl, {
103→        requestInit,
104→      });
105→  }
106→}
107→
108→// ---------------------------------------------------------------------------
109→// Client operations
110→// ---------------------------------------------------------------------------
111→
112→/**
113→ * Connect to an MCP server, perform the initialize handshake,
114→ * and return the client with server metadata.
115→ *
116→ * Uses AbortController with 10s timeout per acceptance criteria.
117→ */
118→async function connectToMcpServer(
119→  url: string,
120→  transportType: McpTransport,
121→  headers?: Record<string, string>,
122→): Promise<McpConnectionResult> {
123→  const transport = createTransport(url, transportType, headers);
124→
125→  const client = new Client(
126→    { name: "brain-tool-registry", version: "1.0.0" },
127→    { capabilities: {} },
128→  );
129→
130→  const abortController = new AbortController();
131→  const timeout = setTimeout(
132→    () => abortController.abort(),
133→    CONNECTION_TIMEOUT_MS,
134→  );
135→
136→  try {
137→    await client.connect(transport, { signal: abortController.signal });
138→  } catch (error) {
139→    // Clean up on connection failure
140→    try {
141→      await client.close();
142→    } catch {
143→      // Ignore cleanup errors
144→    }
145→
146→    if (abortController.signal.aborted) {
147→      throw new Error(
148→        `MCP connection timeout: failed to connect to ${url} within ${CONNECTION_TIMEOUT_MS}ms`,
149→      );
150→    }
151→    throw error;
152→  } finally {
153→    clearTimeout(timeout);
154→  }
155→
156→  const serverInfo = client.getServerVersion() ?? {
157→    name: "unknown",
158→    version: "unknown",
159→  };
160→  const capabilities = client.getServerCapabilities() ?? {};
161→
162→  return { client, serverInfo, capabilities };
163→}
164→
165→/**
166→ * Fetch the list of tools from a connected MCP client.
167→ */
168→async function fetchToolList(client: Client): Promise<ToolListResult> {
169→  return client.listTools();
170→}
171→
172→/**
173→ * Call a tool on a connected MCP client.
174→ */
175→async function callTool(
176→  client: Client,
177→  name: string,
178→  args: Record<string, unknown>,
179→): Promise<CallToolResult> {
180→  return client.callTool({ name, arguments: args });
181→}
182→
183→/**
184→ * Gracefully disconnect from an MCP server.
185→ */
186→async function disconnectMcpServer(client: Client): Promise<void> {
187→  await client.close();
188→}
189→
190→// ---------------------------------------------------------------------------
191→// Factory constructor
192→// ---------------------------------------------------------------------------
193→
194→/**
195→ * Create the production McpClientFactory.
196→ * This is the real implementation wired into ServerDependencies.
197→ */
198→export function createMcpClientFactory(): McpClientFactory {
199→  return {
200→    connect: connectToMcpServer,
201→    fetchToolList,
202→    callTool,
203→    disconnect: disconnectMcpServer,
204→  };
205→}
206→
207→// ---------------------------------------------------------------------------
208→// Internal helpers
209→// ---------------------------------------------------------------------------
210→
211→/**
212→ * Create a fetch wrapper that injects auth headers into SSE EventSource requests.
213→ * The SSE transport's eventSourceInit.fetch is called for the initial GET request.
214→ */
215→function createFetchWithHeaders(
216→  headers: Record<string, string>,
217→): (input: string | URL | Request, init?: RequestInit) => Promise<Response> {
218→  return (input, init) => {
219→    const mergedHeaders = new Headers(init?.headers);
220→    for (const [key, value] of Object.entries(headers)) {
221→      mergedHeaders.set(key, value);
222→    }
223→    return fetch(input, { ...init, headers: mergedHeaders });
224→  };
225→}
