 28→// ---------------------------------------------------------------------------
 29→// Public types for pure functions
 30→// ---------------------------------------------------------------------------
 31→
 32→/**
 33→ * A tool as reported by the remote MCP server (from client.listTools()).
 34→ */
 35→export type RemoteTool = {
 36→  name: string;
 37→  description: string;
 38→  inputSchema: Record<string, unknown>;
 39→  outputSchema?: Record<string, unknown>;
 40→  annotations?: Record<string, unknown>;
 41→};
 42→
 43→/**
 44→ * Minimal shape of an existing local mcp_tool record needed for diffing.
 45→ */
 46→export type ExistingToolRecord = {
 47→  name: string;
 48→  description: string;
 49→  input_schema: Record<string, unknown>;
 50→  output_schema?: Record<string, unknown>;
 51→  risk_level: string;
 52→  status: string;
 53→};
 54→
 55→/**
 56→ * Result of applying sync actions to the database.
 57→ */
 58→export type SyncApplyResult = {
 59→  created: number;
 60→  updated: number;
 61→  disabled: number;
 62→  unchanged: number;
 63→  tools: ToolSyncDetail[];
 64→};
 65→
 66→// ---------------------------------------------------------------------------
 67→// Pure functions
 68→// ---------------------------------------------------------------------------
 69→
 70→/**
 71→ * Infer risk level from MCP tool annotations.
 72→ *
 73→ * Priority:
 74→ *   1. destructiveHint === true  -> "high"
 75→ *   2. readOnlyHint === true     -> "low"
 76→ *   3. idempotentHint === true   -> "low"
 77→ *   4. default                   -> "medium"
 78→ */
 79→export function inferRiskLevel(
 80→  annotations: Record<string, unknown> | undefined,
 81→): ToolRiskLevel {
 82→  if (!annotations) return "medium";
 83→
 84→  if (annotations.destructiveHint === true) return "high";
 85→  if (annotations.readOnlyHint === true) return "low";
 86→  if (annotations.idempotentHint === true) return "low";
 87→
 88→  return "medium";
 89→}
