  6→// ---------------------------------------------------------------------------
  7→// Row types
  8→// ---------------------------------------------------------------------------
  9→
 10→export type McpServerRow = {
 11→  readonly id: RecordId<"mcp_server", string>;
 12→  readonly name: string;
 13→  readonly url: string;
 14→  readonly transport: string;
 15→  readonly workspace: RecordId<"workspace", string>;
 16→  readonly provider?: RecordId<"credential_provider", string>;
 17→  readonly last_status?: string;
 18→  readonly last_error?: string;
 19→  readonly server_info?: Record<string, unknown>;
 20→  readonly capabilities?: Record<string, unknown>;
 21→  readonly last_discovery?: Date | string;
