 27→// Queries
 28→// ---------------------------------------------------------------------------
 29→
 30→/**
 31→ * Check if an mcp_server with the given name already exists in the workspace.
 32→ */
 33→export async function serverNameExists(
 34→  surreal: Surreal,
 35→  workspaceRecord: RecordId<"workspace", string>,
 36→  name: string,
 37→): Promise<boolean> {
 38→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
 39→    `SELECT id FROM mcp_server WHERE workspace = $ws AND name = $name LIMIT 1;`,
 40→    { ws: workspaceRecord, name },
 41→  );
 42→  return (results[0] ?? []).length > 0;
 43→}
 44→
 45→/**
 46→ * Create an mcp_server record.
 47→ */
 48→export async function createMcpServer(
 49→  surreal: Surreal,
 50→  workspaceRecord: RecordId<"workspace", string>,
 51→  input: {
 52→    name: string;
 53→    url: string;
 54→    transport: string;
 55→    providerRecord?: RecordId<"credential_provider", string>;
 56→  },
 57→): Promise<McpServerRow> {
 58→  const serverId = crypto.randomUUID();
 59→  const serverRecord = new RecordId("mcp_server", serverId);
 60→
 61→  const content: Record<string, unknown> = {
 62→    name: input.name,
 63→    url: input.url,
 64→    transport: input.transport,
 65→    workspace: workspaceRecord,
 66→    tool_count: 0,
 67→    created_at: new Date(),
 68→  };
 69→
 70→  if (input.providerRecord) {
 71→    content.provider = input.providerRecord;
 72→  }
 73→
 74→  await surreal.query(`CREATE $server CONTENT $content;`, {
 75→    server: serverRecord,
 76→    content,
 77→  });
 78→
 79→  return {
 80→    id: serverRecord,
 81→    ...content,
 82→  } as unknown as McpServerRow;
 83→}
