 85→/**
 86→ * List all mcp_servers in a workspace.
 87→ */
 88→export async function listMcpServers(
 89→  surreal: Surreal,
 90→  workspaceRecord: RecordId<"workspace", string>,
 91→): Promise<McpServerRow[]> {
 92→  const results = await surreal.query<[McpServerRow[]]>(
 93→    `SELECT * FROM mcp_server WHERE workspace = $ws ORDER BY created_at DESC;`,
 94→    { ws: workspaceRecord },
 95→  );
 96→  return results[0] ?? [];
 97→}
