 99→/**
100→ * Get a single mcp_server by ID, scoped to workspace.
101→ */
102→export async function getMcpServerById(
103→  surreal: Surreal,
104→  serverRecord: RecordId<"mcp_server", string>,
105→  workspaceRecord: RecordId<"workspace", string>,
106→): Promise<McpServerRow | undefined> {
107→  const results = await surreal.query<[McpServerRow[]]>(
108→    `SELECT * FROM $server WHERE workspace = $ws;`,
109→    { server: serverRecord, ws: workspaceRecord },
110→  );
111→  return (results[0] ?? [])[0];
112→}
