114→/**
115→ * Delete an mcp_server and disable all tools linked via source_server.
116→ * Returns true if the server existed and was deleted.
117→ */
118→export async function deleteMcpServer(
119→  surreal: Surreal,
120→  serverRecord: RecordId<"mcp_server", string>,
121→  workspaceRecord: RecordId<"workspace", string>,
122→): Promise<boolean> {
123→  // Check existence first (workspace-scoped)
124→  const existing = await getMcpServerById(surreal, serverRecord, workspaceRecord);
125→  if (!existing) {
126→    return false;
127→  }
128→
129→  // Disable all tools linked to this server, then delete the server
130→  await surreal.query(
131→    `UPDATE mcp_tool SET status = "disabled" WHERE source_server = $server;
132→     DELETE $server;`,
133→    { server: serverRecord },
134→  );
135→
136→  return true;
137→}
