  1→/**
  2→ * HTTP routes for MCP server management.
  3→ *
  4→ * POST   /api/workspaces/:wsId/mcp-servers              (register server)
  5→ * GET    /api/workspaces/:wsId/mcp-servers               (list servers)
  6→ * GET    /api/workspaces/:wsId/mcp-servers/:serverId     (server detail)
  7→ * DELETE /api/workspaces/:wsId/mcp-servers/:serverId     (remove server)
  8→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/discover  (dry-run discovery)
  9→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/sync      (apply sync)
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import { jsonError, jsonResponse } from "../http/response";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 16→import {
 17→  validateMcpServerUrl,
 18→  validateMcpServerTransport,
 19→} from "./server-validation";
 20→import {
 21→  serverNameExists,
 22→  createMcpServer,
 23→  listMcpServers,
 24→  getMcpServerById,
 25→  deleteMcpServer,
 26→  type McpServerRow,
 27→} from "./server-queries";
 28→import { getProviderById } from "./queries";
 29→import { discoverTools } from "./discovery";
 30→import type { McpServerRecord } from "./types";
 31→import { log } from "../telemetry/logger";
 32→
 33→// ---------------------------------------------------------------------------
 34→// Response mapping -- DB record to API shape
 35→// ---------------------------------------------------------------------------
 36→
 37→type McpServerResponse = {
 38→  id: string;
 39→  name: string;
 40→  url: string;
 41→  transport: string;
 42→  tool_count: number;
 43→  last_status?: string;
 44→  last_error?: string;
 45→  last_discovery?: string;
 46→  provider_id?: string;
 47→  provider_name?: string;
 48→  created_at: string;
 49→};
 50→
 51→function toMcpServerResponse(
 52→  row: McpServerRow,
 53→  providerName?: string,
 54→): McpServerResponse {
 55→  const response: McpServerResponse = {
 56→    id: row.id.id as string,
 57→    name: row.name,
 58→    url: row.url,
 59→    transport: row.transport,
 60→    tool_count: row.tool_count,
 61→    created_at: row.created_at instanceof Date
 62→      ? row.created_at.toISOString()
 63→      : String(row.created_at),
 64→  };
 65→
 66→  if (row.last_status) {
 67→    response.last_status = row.last_status;
 68→  }
 69→  if (row.last_error) {
 70→    response.last_error = row.last_error;
 71→  }
 72→  if (row.last_discovery) {
 73→    response.last_discovery = row.last_discovery instanceof Date
 74→      ? row.last_discovery.toISOString()
 75→      : String(row.last_discovery);
 76→  }
 77→  if (row.provider) {
 78→    response.provider_id = row.provider.id as string;
 79→    if (providerName) {
 80→      response.provider_name = providerName;
 81→    }
 82→  }
 83→
 84→  return response;
 85→}
 86→
 87→// ---------------------------------------------------------------------------
 88→// Input type
 89→// ---------------------------------------------------------------------------
 90→
 91→type CreateMcpServerInput = {
 92→  name?: string;
 93→  url?: string;
 94→  transport?: string;
 95→  provider_id?: string;
 96→};
 97→
 98→// ---------------------------------------------------------------------------
 99→// Route handlers
100→// ---------------------------------------------------------------------------
101→
102→export function createServerRouteHandlers(deps: ServerDependencies) {
103→  async function handleCreateServer(
104→    workspaceId: string,
105→    request: Request,
106→  ): Promise<Response> {
107→    let workspaceRecord: RecordId<"workspace", string>;
108→    try {
109→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
110→    } catch (error) {
111→      if (error instanceof HttpError) {
112→        return jsonError(error.message, error.status);
113→      }
114→      log.error("mcp-server.create", "Failed to resolve workspace", error, { workspaceId });
115→      return jsonError("internal error", 500);
116→    }
117→
118→    let body: CreateMcpServerInput;
119→    try {
120→      body = await request.json() as CreateMcpServerInput;
121→    } catch {
122→      return jsonError("invalid JSON body", 400);
123→    }
124→
125→    // Validate name
126→    if (!body.name || typeof body.name !== "string" || body.name.trim().length === 0) {
127→      return jsonError("name is required", 400);
128→    }
129→
130→    // Validate URL
131→    const urlString = body.url ?? "";
132→    const urlValidation = validateMcpServerUrl(urlString);
133→    if (!urlValidation.ok) {
134→      return jsonError(urlValidation.error, 400);
135→    }
136→
137→    // Validate transport (default to streamable-http)
138→    const transport = body.transport ?? "streamable-http";
139→    const transportValidation = validateMcpServerTransport(transport);
140→    if (!transportValidation.ok) {
141→      return jsonError(transportValidation.error, 400);
142→    }
143→
144→    // Validate provider link if specified
145→    let providerRecord: RecordId<"credential_provider", string> | undefined;
146→    let providerName: string | undefined;
147→    if (body.provider_id) {
148→      const provider = await getProviderById(deps.surreal, body.provider_id);
149→      if (!provider) {
150→        return jsonError("Credential provider not found", 404);
151→      }
152→      providerRecord = new RecordId("credential_provider", body.provider_id);
153→      providerName = (provider as unknown as { display_name?: string }).display_name;
154→    }
155→
156→    // Check duplicate name
157→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
158→    if (duplicate) {
159→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
160→    }
161→
162→    // Create server
163→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
164→      name: body.name,
165→      url: urlString,
166→      transport,
167→      providerRecord,
168→    });
169→
170→    return jsonResponse(toMcpServerResponse(row, providerName), 201);
171→  }
172→
173→  async function handleListServers(
174→    workspaceId: string,
175→    _request: Request,
176→  ): Promise<Response> {
177→    let workspaceRecord: RecordId<"workspace", string>;
178→    try {
179→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
180→    } catch (error) {
181→      if (error instanceof HttpError) {
182→        return jsonError(error.message, error.status);
183→      }
184→      log.error("mcp-server.list", "Failed to resolve workspace", error, { workspaceId });
185→      return jsonError("internal error", 500);
186→    }
187→
188→    const rows = await listMcpServers(deps.surreal, workspaceRecord);
189→    const servers = rows.map((row) => toMcpServerResponse(row));
190→    return jsonResponse({ servers }, 200);
191→  }
192→
193→  async function handleGetServerDetail(
194→    workspaceId: string,
195→    serverId: string,
196→    _request: Request,
197→  ): Promise<Response> {
198→    let workspaceRecord: RecordId<"workspace", string>;
199→    try {
200→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
201→    } catch (error) {
202→      if (error instanceof HttpError) {
203→        return jsonError(error.message, error.status);
204→      }
205→      log.error("mcp-server.detail", "Failed to resolve workspace", error, { workspaceId });
206→      return jsonError("internal error", 500);
207→    }
208→
209→    const serverRecord = new RecordId("mcp_server", serverId);
210→    const row = await getMcpServerById(deps.surreal, serverRecord, workspaceRecord);
211→
212→    if (!row) {
213→      return jsonError("MCP server not found", 404);
214→    }
215→
216→    return jsonResponse(toMcpServerResponse(row), 200);
217→  }
218→
219→  async function handleDeleteServer(
220→    workspaceId: string,
221→    serverId: string,
222→    _request: Request,
223→  ): Promise<Response> {
224→    let workspaceRecord: RecordId<"workspace", string>;
225→    try {
226→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
227→    } catch (error) {
228→      if (error instanceof HttpError) {
229→        return jsonError(error.message, error.status);
230→      }
231→      log.error("mcp-server.delete", "Failed to resolve workspace", error, { workspaceId });
232→      return jsonError("internal error", 500);
233→    }
234→
235→    const serverRecord = new RecordId("mcp_server", serverId);
236→    const deleted = await deleteMcpServer(deps.surreal, serverRecord, workspaceRecord);
237→
238→    if (!deleted) {
239→      return jsonError("MCP server not found", 404);
240→    }
241→
242→    return jsonResponse({ deleted: true }, 200);
243→  }
244→
245→  /**
246→   * Resolve server record for discovery/sync operations.
247→   * Returns the server row or an error response.
248→   */
249→  async function resolveServer(
250→    workspaceId: string,
251→    serverId: string,
252→  ): Promise<{ server: McpServerRow } | { error: Response }> {
253→    let workspaceRecord: RecordId<"workspace", string>;
254→    try {
255→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
256→    } catch (error) {
257→      if (error instanceof HttpError) {
258→        return { error: jsonError(error.message, error.status) };
259→      }
260→      log.error("mcp-server.resolve", "Failed to resolve workspace", error, { workspaceId });
261→      return { error: jsonError("internal error", 500) };
262→    }
263→
264→    const serverRecord = new RecordId("mcp_server", serverId);
265→    const row = await getMcpServerById(deps.surreal, serverRecord, workspaceRecord);
266→
267→    if (!row) {
268→      return { error: jsonError("MCP server not found", 404) };
269→    }
270→
271→    return { server: row };
272→  }
273→
274→  async function handleDiscover(
275→    workspaceId: string,
276→    serverId: string,
277→    _request: Request,
278→  ): Promise<Response> {
279→    const resolved = await resolveServer(workspaceId, serverId);
280→    if ("error" in resolved) return resolved.error;
281→
282→    const server = resolved.server as unknown as McpServerRecord;
283→
284→    try {
285→      const result = await discoverTools(
286→        { surreal: deps.surreal, mcpClientFactory: deps.mcpClientFactory },
287→        server,
288→        { dryRun: true },
289→      );
290→
291→      return jsonResponse(result, 200);
292→    } catch (error) {
293→      log.error("mcp-server.discover", "Discovery failed", error, { serverId });
294→      return jsonError(
295→        `Failed to connect to MCP server: ${error instanceof Error ? error.message : "unknown error"}`,
296→        502,
297→      );
298→    }
299→  }
300→
301→  async function handleSync(
302→    workspaceId: string,
303→    serverId: string,
304→    request: Request,
305→  ): Promise<Response> {
306→    const resolved = await resolveServer(workspaceId, serverId);
307→    if ("error" in resolved) return resolved.error;
308→
309→    const server = resolved.server as unknown as McpServerRecord;
310→
311→    let selectedTools: string[] | undefined;
312→    try {
313→      const body = await request.json() as { selected_tools?: string[] };
314→      selectedTools = body.selected_tools;
315→    } catch {
316→      // Empty body is valid -- sync all tools
317→    }
318→
319→    try {
320→      const result = await discoverTools(
321→        { surreal: deps.surreal, mcpClientFactory: deps.mcpClientFactory },
322→        server,
323→        { dryRun: false, selectedTools },
324→      );
325→
326→      return jsonResponse(result, 200);
327→    } catch (error) {
328→      log.error("mcp-server.sync", "Sync failed", error, { serverId });
329→      return jsonError(
330→        `Failed to connect to MCP server: ${error instanceof Error ? error.message : "unknown error"}`,
331→        502,
332→      );
333→    }
334→  }
335→
336→  return {
337→    handleCreateServer,
338→    handleListServers,
339→    handleGetServerDetail,
340→    handleDeleteServer,
341→    handleDiscover,
342→    handleSync,
343→  };
344→}
