 40→type McpServerResponse = {
 41→  id: string;
 42→  name: string;
 43→  url: string;
 44→  transport: string;
 45→  auth_mode: string;
 46→  has_static_headers: boolean;
 47→  tool_count: number;
 48→  last_status?: string;
 49→  last_error?: string;
 50→  last_discovery?: string;
 51→  provider_id?: string;
 52→  provider_name?: string;
 53→  created_at: string;
 54→};
 55→
 56→function toMcpServerResponse(
 57→  row: McpServerRow,
 58→  providerName?: string,
 59→): McpServerResponse {
 60→  const response: McpServerResponse = {
 61→    id: row.id.id as string,
 62→    name: row.name,
 63→    url: row.url,
 64→    transport: row.transport,
 65→    auth_mode: row.auth_mode ?? "none",
 66→    has_static_headers: Array.isArray(row.static_headers) && row.static_headers.length > 0,
 67→    tool_count: row.tool_count,
 68→    created_at: row.created_at instanceof Date
 69→      ? row.created_at.toISOString()
 70→      : String(row.created_at),
 71→  };
 72→
 73→  if (row.last_status) {
 74→    response.last_status = row.last_status;
 75→  }
 76→  if (row.last_error) {
 77→    response.last_error = row.last_error;
 78→  }
 79→  if (row.last_discovery) {
 80→    response.last_discovery = row.last_discovery instanceof Date
 81→      ? row.last_discovery.toISOString()
 82→      : String(row.last_discovery);
 83→  }
 84→  if (row.provider) {
 85→    response.provider_id = row.provider.id as string;
 86→    if (providerName) {
 87→      response.provider_name = providerName;
 88→    }
 89→  }
 90→
 91→  return response;
 92→}
