110→
111→export function createServerRouteHandlers(deps: ServerDependencies) {
112→  async function handleCreateServer(
113→    workspaceId: string,
114→    request: Request,
115→  ): Promise<Response> {
116→    let workspaceRecord: RecordId<"workspace", string>;
117→    try {
118→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
119→    } catch (error) {
120→      if (error instanceof HttpError) {
121→        return jsonError(error.message, error.status);
122→      }
123→      log.error("mcp-server.create", "Failed to resolve workspace", error, { workspaceId });
124→      return jsonError("internal error", 500);
125→    }
126→
127→    let body: CreateMcpServerInput;
128→    try {
129→      body = await request.json() as CreateMcpServerInput;
130→    } catch {
131→      return jsonError("invalid JSON body", 400);
132→    }
133→
134→    // Validate name
135→    if (!body.name || typeof body.name !== "string" || body.name.trim().length === 0) {
136→      return jsonError("name is required", 400);
137→    }
138→
139→    // Validate URL
140→    const urlString = body.url ?? "";
141→    const urlValidation = validateMcpServerUrl(urlString);
142→    if (!urlValidation.ok) {
143→      return jsonError(urlValidation.error, 400);
144→    }
145→
146→    // Validate transport (default to streamable-http)
147→    const transport = body.transport ?? "streamable-http";
148→    const transportValidation = validateMcpServerTransport(transport);
149→    if (!transportValidation.ok) {
150→      return jsonError(transportValidation.error, 400);
151→    }
152→
153→    // Validate provider link if specified
154→    let providerRecord: RecordId<"credential_provider", string> | undefined;
155→    let providerName: string | undefined;
156→    if (body.provider_id) {
157→      const provider = await getProviderById(deps.surreal, body.provider_id);
158→      if (!provider) {
159→        return jsonError("Credential provider not found", 404);
160→      }
161→      providerRecord = new RecordId("credential_provider", body.provider_id);
162→      providerName = (provider as unknown as { display_name?: string }).display_name;
163→    }
164→
165→    // Validate auth_mode
166→    const authMode = body.auth_mode ?? "none";
167→    if (!VALID_AUTH_MODES.has(authMode)) {
168→      return jsonError(`Invalid auth_mode: must be one of none, static_headers, oauth, provider`, 400);
169→    }
170→
171→    // Encrypt static headers if provided
172→    let encryptedHeaders: EncryptedHeaderEntry[] | undefined;
173→    if (authMode === "static_headers") {
174→      const encryptionKey = deps.config.toolEncryptionKey;
175→      if (!encryptionKey) {
176→        log.error("mcp-server.create", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
177→        return jsonError("Server encryption not configured", 500);
178→      }
179→      if (!Array.isArray(body.static_headers) || body.static_headers.length === 0) {
180→        return jsonError("static_headers required when auth_mode is static_headers", 400);
181→      }
182→      encryptedHeaders = body.static_headers.map((header) => {
183→        if (!header.name || !header.value) {
184→          throw new HttpError(400, "Each static header must have name and value");
185→        }
186→        return {
187→          name: header.name,
188→          value_encrypted: encryptSecret(header.value, encryptionKey),
189→        };
190→      });
191→    }
192→
193→    // Check duplicate name
194→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
195→    if (duplicate) {
196→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
197→    }
198→
199→    // Create server
200→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
201→      name: body.name,
202→      url: urlString,
203→      transport,
204→      authMode,
205→      staticHeaders: encryptedHeaders,
206→      providerRecord,
207→    });
208→
209→    return jsonResponse(toMcpServerResponse(row, providerName), 201);
210→  }
211→
212→  async function handleListServers(
213→    workspaceId: string,
214→    _request: Request,
215→  ): Promise<Response> {
216→    let workspaceRecord: RecordId<"workspace", string>;
217→    try {
218→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
219→    } catch (error) {
220→      if (error instanceof HttpError) {
221→        return jsonError(error.message, error.status);
222→      }
223→      log.error("mcp-server.list", "Failed to resolve workspace", error, { workspaceId });
224→      return jsonError("internal error", 500);
225→    }
