284→  /**
285→   * Resolve server record for discovery/sync operations.
286→   * Returns the server row or an error response.
287→   */
288→  async function resolveServer(
289→    workspaceId: string,
290→    serverId: string,
291→  ): Promise<{ server: McpServerRow } | { error: Response }> {
292→    let workspaceRecord: RecordId<"workspace", string>;
293→    try {
294→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
295→    } catch (error) {
296→      if (error instanceof HttpError) {
297→        return { error: jsonError(error.message, error.status) };
298→      }
299→      log.error("mcp-server.resolve", "Failed to resolve workspace", error, { workspaceId });
300→      return { error: jsonError("internal error", 500) };
301→    }
302→
303→    const serverRecord = new RecordId("mcp_server", serverId);
304→    const row = await getMcpServerById(deps.surreal, serverRecord, workspaceRecord);
305→
306→    if (!row) {
307→      return { error: jsonError("MCP server not found", 404) };
308→    }
309→
310→    return { server: row };
311→  }
312→
313→  async function handleDiscover(
314→    workspaceId: string,
315→    serverId: string,
316→    _request: Request,
317→  ): Promise<Response> {
318→    const resolved = await resolveServer(workspaceId, serverId);
319→    if ("error" in resolved) return resolved.error;
320→
321→    const server = resolved.server as unknown as McpServerRecord;
322→
323→    try {
324→      const result = await discoverTools(
325→        { surreal: deps.surreal, mcpClientFactory: deps.mcpClientFactory },
326→        server,
327→        { dryRun: true },
328→      );
329→
330→      return jsonResponse(result, 200);
331→    } catch (error) {
332→      log.error("mcp-server.discover", "Discovery failed", error, { serverId });
333→      return jsonError(
334→        `Failed to connect to MCP server: ${error instanceof Error ? error.message : "unknown error"}`,
335→        502,
336→      );
337→    }
338→  }
339→
340→  async function handleSync(
341→    workspaceId: string,
342→    serverId: string,
343→    request: Request,
344→  ): Promise<Response> {
345→    const resolved = await resolveServer(workspaceId, serverId);
346→    if ("error" in resolved) return resolved.error;
347→
348→    const server = resolved.server as unknown as McpServerRecord;
349→
350→    let selectedTools: string[] | undefined;
351→    try {
352→      const body = await request.json() as { selected_tools?: string[] };
353→      selectedTools = body.selected_tools;
354→    } catch {
355→      // Empty body is valid -- sync all tools
356→    }
357→
358→    try {
359→      const result = await discoverTools(
360→        { surreal: deps.surreal, mcpClientFactory: deps.mcpClientFactory },
361→        server,
362→        { dryRun: false, selectedTools },
363→      );
364→
365→      return jsonResponse(result, 200);
366→    } catch (error) {
367→      log.error("mcp-server.sync", "Sync failed", error, { serverId });
368→      return jsonError(
369→        `Failed to connect to MCP server: ${error instanceof Error ? error.message : "unknown error"}`,
370→        502,
371→      );
372→    }
373→  }
374→
375→  return {
376→    handleCreateServer,
377→    handleListServers,
378→    handleGetServerDetail,
379→    handleDeleteServer,
380→    handleDiscover,
381→    handleSync,
382→  };
383→}
